message.content:
[
  {
    "title": "ALLBUS – German General Social Survey (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations",
      "Higher and further education"
    ],
    "description": "Repeated cross-sectional surveys of the German population since 1980, covering social structure, values and attitudes, including political behavior, trust in institutions, and occasional items on education and education policy."
  },
  {
    "title": "GLES – German Longitudinal Election Study (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations"
    ],
    "description": "Comprehensive election study program around German federal elections, including pre- and post-election surveys, rolling cross-sections, and campaign panels on voting behavior, party preferences, and evaluations of government and political institutions."
  },
  {
    "title": "Eurobarometer (Standard and Special) (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations",
      "Higher and further education"
    ],
    "description": "Cross-national public opinion surveys in EU member states on politics, institutions, policy issues, and social topics. Various waves include items on governance, democratic satisfaction, and occasionally on education and higher education themes."
  },
  {
    "title": "ISSP – Role of Government (Series)",
    "host": "GESIS",
    "topics": [
      "Government, political systems and organisations",
      "Political behaviour and attitudes"
    ],
    "description": "International Social Survey Programme module repeated over multiple years, examining attitudes towards the role, responsibilities, and performance of government, public spending, taxation, and regulation."
  },
  {
    "title": "ISSP – Citizenship (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations"
    ],
    "description": "ISSP module focusing on civic engagement, political participation, rights and responsibilities, political efficacy, and trust in institutions across countries and time."
  },
  {
    "title": "European Values Study (EVS) (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations"
    ],
    "description": "Long-running cross-national survey of values and beliefs in Europe, including democracy, political trust, institutional confidence, social capital, and civic norms."
  },
  {
    "title": "Politbarometer (Germany) (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations"
    ],
    "description": "Regular German public opinion series measuring party support, government approval, policy preferences, and perceptions of political actors and institutions."
  },
  {
    "title": "German National Election Studies (Bundestagswahlstudien) (Series)",
    "host": "GESIS",
    "topics": [
      "Political behaviour and attitudes",
      "Government, political systems and organisations"
    ],
    "description": "Historical election study series preceding and complementing GLES, documenting voter behavior, party identification, issue orientations, and evaluations of government around German federal elections."
  }
]
